import itertools

def get_all_polyominoes(n):
    # Generate all possible polyominoes of size n
    polyominoes = set()
    for p in itertools.product([0, 1], repeat=n*4):
        grid = [list(p[i:i+4]) for i in range(0, len(p), 4)]
        if sum(sum(row) for row in grid) == n:
            # Check if the polyomino is connected
            if is_connected(grid):
                # Normalize the polyomino
                normalized = normalize(grid)
                polyominoes.add(tuple(map(tuple, normalized)))
    return polyominoes

def is_connected(grid):
    # Check if the polyomino is connected
    visited = [[False]*4 for _ in range(4)]
    for i in range(4):
        for j in range(4):
            if grid[i][j] == 1 and not visited[i][j]:
                if not dfs(grid, visited, i, j):
                    return False
    return True

def dfs(grid, visited, i, j):
    # Perform a depth-first search
    if i < 0 or i >= 4 or j < 0 or j >= 4 or grid[i][j] == 0 or visited[i][j]:
        return True
    visited[i][j] = True
    for di, dj in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
        if not dfs(grid, visited, i+di, j+dj):
            return False
    return True

