    return [list(reversed(i)) for i in zip(*grid)]

def flip(grid):
    # Flip the polyomino horizontally
    return [list(reversed(i)) for i in grid]

def is_min(grid):
    # Check if the polyomino is in its minimum rotation and flip
    for i in range(4):
        for j in range(4):
            if grid[i][j] == 1:
                return i == 0 or j == 0
