import itertools

def get_rotations(piece):
    rotations = set()
    for _ in range(4):
        piece = tuple(zip(*piece[::-1]))
        rotations.add(piece)
    return rotations

def get_flips(piece):
    flips = set()
    flips.add(piece)
    flips.add(tuple((x, -y) for x, y in piece))
    return flips

def get_unique_pieces(squares):
    pieces = set()
    for combo in itertools.combinations_with_replacement([(x, y) for x in range(squares) for y in range(squares)], squares):
        piece = tuple(sorted(combo))
        rotations = get_rotations(piece)
        flips = set()
        for rotation in rotations:
            flips.update(get_flips(rotation))
        pieces.add(min(flips))
    return pieces

def get_blokus_pieces(max_squares):
    pieces = []
    for squares in range(1, max_squares + 1):
        unique_pieces = get_unique_pieces(squares)
        connected_pieces = []
        for piece in unique_pieces:
            connected = True
            for x, y in piece:
                adjacent = [(x + 1, y), (x - 1, y), (x, y + 1), (x, y - 1)]
                adjacent_in_piece = [point for point in adjacent if point in piece]
                if len(adjacent_in_piece) == 0 and (x, y)!= min(piece):
                    connected = False
                    break
            if connected:
                connected_pieces.append(piece)
        pieces.append((squares, connected_pieces))
    return pieces

