def get_polyominoes(n):
    polyominoes = set()
    for p in itertools.product(range(2), repeat=n):
        if sum(p) != n:
            continue
        piece = []
        x, y = 0, 0
        for i in range(n):
            if p[i] == 1:
                piece.append((x, y))
                x += 1
            else:
                x = 0
                y += 1
        normalized_piece = normalize(piece)
        polyominoes.add(normalized_piece)
    return polyominoes

