def generate_combinations(n, max_size):
    def generate_combinations_recursive(n, max_size, current_combination, start_index):
        if len(current_combination) > max_size:
            return
        if len(current_combination) > 0:
            yield current_combination[:]
        for i in range(start_index, n + 1):
            current_combination.append(i)
            yield from generate_combinations_recursive(n, max_size, current_combination, i)
            current_combination.pop()

    yield from generate_combinations_recursive(n, max_size, [], 1)

def main():
    n = 5
    max_size = 5
    for combination in generate_combinations(n, max_size):
        print(combination)

if __name__ == "__main__":
    main()

def generate_pattern(n):
    pattern = []
    for i in range(1, n+1):
        row = []
        for j in range(i):
            row.append(f"{i}x{j+1}")
        pattern.append(row)
    return pattern

def print_pattern(pattern):
    for row in pattern:
        print(" ".join(row))

def main():
    n = 5
    pattern = generate_pattern(n)
    print_pattern(pattern)

