def calculate_combinations(n, k):
    if k > n:
        return 0
    result = 1
    for i in range(1, k + 1):
        result = result * (n - i + 1) // i
    return result

def generate_pascal_triangle(rows):
    triangle = []
    for i in range(rows):
        row = [calculate_combinations(i, j) for j in range(i + 1)]
        triangle.append(row)
    return triangle

def print_pascal_triangle(triangle):
    for row in triangle:
        print(' '.join(str(num) for num in row))

def main():
