def calculate_combinations(n, max_size):
    combinations = []
    for i in range(1, max_size + 1):
        combinations.append((n, i))
    return combinations

def generate_possibilities(n, max_size):
    possibilities = []
    for combination in calculate_combinations(n, max_size):
        num, size = combination
        if size == 1:
            possibilities.append((num, 1))
        else:
            for i in range(1, num + 1):
                possibilities.append((i, size))
    return possibilities

def filter_possibilities(possibilities, max_sum):
    filtered_possibilities = []
    for possibility in possibilities:
        num, size = possibility
        if num * size <= max_sum:
            filtered_possibilities.append(possibility)
    return filtered_possibilities

def main():
    n = 5
    max_size = 5
    max_sum = 5
    possibilities = generate_possibilities(n, max_size)
    filtered_possibilities = filter_possibilities(possibilities, max_sum)
    for possibility in filtered_possibilities:
        print(possibility)

main()
